            rsto_125      => rst125,
            rsto_ipb      => rst_ipb,
            rsto_aux      => rst_aux,
            rsto_eth      => rst_phy,
            rsto_ipb_ctrl => rst_ipb_ctrl,
            onehz         => onehz
            );

    clk_ipb   <= clk_ipb_i;  -- Best to align delta delays on all clocks for simulation
    clk_ipb_o <= clk_ipb_i;
    rst_ipb_o <= rst_ipb;
    clk_aux_o <= clk_aux;
    rst_aux_o <= rst_aux;
    locked    <= clk_locked and eth_locked;

    eth : entity work.eth_sgmii_lvds_vcu118
        port map(
            -- free running 125 MHz clk
            clk125_fr              => osc_clk_125,
            -- reset in
            rst                    => rst_phy,
            -- reset out
            rst_o                  => rst_eth,
            -- status
            locked                 => eth_locked,
            debug_leds(7 downto 0) => debug_leds(7 downto 0),
            dip_sw                 => dip_sw,
            -- eth clock out
            clk125_eth             => clk_eth,
            -- mac ports (go to ipbus)
            tx_data                => tx_data,
            rx_data                => rx_data,
            tx_valid               => tx_valid,
            tx_last                => tx_last,
            tx_error               => tx_error,
            tx_ready               => tx_ready,
            rx_valid               => rx_valid,
            rx_last                => rx_last,
            rx_error               => rx_error,
            -- eth external ports (go to top level ports)
            sgmii_clk_p            => sgmii_clk_p,
            sgmii_clk_n            => sgmii_clk_n,
            sgmii_txp              => sgmii_txp,
            sgmii_txn              => sgmii_txn,
            sgmii_rxp              => sgmii_rxp,
            sgmii_rxn              => sgmii_rxn,
            phy_on                 => phy_on,
            phy_resetb             => phy_resetb,
            phy_mdio               => phy_mdio,
            phy_mdc                => phy_mdc
            );


    ipbus : entity work.ipbus_ctrl
        generic map(
            DHCP_RARP => DHCP_not_RARP
        )
        port map(
            mac_clk      => clk_eth,
            rst_macclk   => rst_eth,
            ipb_clk      => clk_ipb_i,
            rst_ipb      => rst_ipb_ctrl,
            mac_rx_data  => rx_data,
            mac_rx_valid => rx_valid,
            mac_rx_last  => rx_last,
            mac_rx_error => rx_error,
            mac_tx_data  => tx_data,
            mac_tx_valid => tx_valid,
            mac_tx_last  => tx_last,
            mac_tx_error => tx_error,
            mac_tx_ready => tx_ready,
            ipb_out      => ipb_out,
            ipb_in       => ipb_in,
            mac_addr     => mac_addr,
            ip_addr      => ip_addr,
            ipam_select  => ipam_select,
            pkt          => pkt
            );

    -- TODO: Add equivalent of 'stretched' "pkt" signal from ku105 design
    leds <= '0' & (locked and onehz);




end rtl;

